434→export const deleteCanvasMarginService = async(marginId, userId) => {
435→    if(!marginId){
436→        throw {status: 400, error: 'marginId is undefined'};
437→    }
438→    if(!userId){
439→        throw {status: 401, error: 'userId is undefined'};
440→    }
441→
442→    const {data: marginItem, error: marginError} = await supabase
443→    .from('canvas_margin_items')
444→    .select('id, journal_id, user_id')
445→    .eq('id', marginId)
446→    .maybeSingle();
447→
448→    if(marginError){
449→        console.error('supabase error while fetching margin item:', marginError.message);
450→        throw {status: 500, error: 'failed to fetch canvas margin item'};
451→    }
452→
453→    if(!marginItem){
454→        throw {status: 404, error: 'canvas margin item not found'};
455→    }
456→
457→    const journal = await assertCanvasJournalAccess(marginItem.journal_id, userId);
458→    const isOwner = marginItem.user_id === userId;
459→    const isCanvasAuthor = journal.user_id === userId;
460→    if(!isOwner && !isCanvasAuthor){
461→        throw {status: 403, error: 'not authorized to delete this margin item'};
462→    }
463→
464→    const {error: deleteError} = await supabase
465→    .from('canvas_margin_items')
466→    .delete()
467→    .eq('id', marginId);
