  22→const extractBearerToken = (authHeader = "") => {
  23→    const trimmed = typeof authHeader === "string" ? authHeader.trim() : "";
  24→    if (!trimmed) return "";
  25→
  26→    const bearerMatch = trimmed.match(/^Bearer\s+(.+)$/i);
  27→    if (bearerMatch?.[1]) {
  28→        return bearerMatch[1].trim();
  29→    }
  30→
  31→    return trimmed;
  32→};
  33→
  34→const resolveAuthUser = async (token) => {
  35→    if (!token) {
  36→        return { user: null, error: null };
  37→    }
  38→
  39→    const { data: authData, error: authError } = await supabase.auth.getUser(token);
  40→    if (authError || !authData?.user?.id) {
  41→        return { user: null, error: authError || new Error("missing user id") };
  42→    }
  43→
  44→    return { user: authData.user, error: null };
  45→};
  46→
  47→const requireAuth = async (req, res, next) => {
  48→    const token = extractBearerToken(req.headers?.authorization);
  49→    if (!token) {
  50→        return res.status(401).json({ error: 'not authorized' });
  51→    }
  52→
  53→    const { user, error } = await resolveAuthUser(token);
  54→    if (error || !user?.id) {
  55→        console.error('auth middleware error:', error?.message || 'missing user id');
  56→        return res.status(401).json({ error: 'not authorized' });
  57→    }
  58→
  59→    req.userId = user.id;
  60→    req.authUser = user;
  61→    return next();
  62→};
  63→
  64→const optionalAuth = async (req, _res, next) => {
  65→    const token = extractBearerToken(req.headers?.authorization);
  66→    if (!token) {
  67→        return next();
  68→    }
  69→
  70→    const { user } = await resolveAuthUser(token);
  71→    if (user?.id) {
  72→        req.userId = user.id;
  73→        req.authUser = user;
  74→    }
  75→
  76→    return next();
  77→};
