1020→    .insert({post_id: post_id, user_id: user_id, comment: reply, parent_id: parent_id})
1021→
1022→    const insertNotifPromise = supabase
1023→    .from('notifications')
1024→    .insert({sender_id: user_id, receiver_id: receiver_id, type: 'reply', journal_id: post_id, read: false})  
1025→
1026→    const [insertNotif, insertReply] = await Promise.all([
1027→        isOwner ? Promise.resolve({error: null}) : insertNotifPromise, 
1028→        insertReplyPromise
