1043→router.get('/getPostReplies/:parent_id', async(req, res) => {
1044→    const {parent_id} = req.params;
1045→    const {limit, before} = req.query;
1046→    
1047→    if(!parent_id){
1048→        console.error('parent_id is undefined');
1049→        return res.status(400).json({error: 'parent_id is undefined'});
1050→    }
1051→
1052→    const parsedLimit = parseInt(limit);
1053→
1054→    if(isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > 20){
1055→        console.error('limit should be intiger or it should be between 1 to 20');
1056→        return res.status(400).json({error: 'limit should be intiger or it should be between 1 to 20'});
1057→    }
1058→
1059→    let query = supabase
1060→    .from('comments')
1061→    .select('*, users(name, image_url, id, user_email, badge)')
1062→    .eq('parent_id', parent_id)
1063→    .order('id', {ascending: false})
1064→    .limit(parsedLimit + 1)
1065→
1066→    if(before){
1067→        query = query.lt('id', before);
1068→    }
1069→
1070→    const {data: getPostReplies, error: getPostRepliesError} = await query;
1071→
1072→    if(getPostRepliesError){
1073→        console.error('supabase error while fetchind replies:', getPostRepliesError.message);
1074→        return res.status(500).json({error: 'supabase error while getting post replies'});
1075→    }
1076→
1077→    const hasMore = getPostReplies.length > parsedLimit;
1078→    const slicedData = hasMore ? getPostReplies.splice(0, parsedLimit) : getPostReplies;
1079→
1080→    return res.status(200).json({data: slicedData, hasMore: hasMore});
1081→})
