 95→const CanvasImageNode = ({canvasImage, stageWidth, stageHeight, isSelected, onSelect, onDragEnd, canInteract}) => {
 96→    const loadedImage = useLoadedImage(canvasImage?.src);
 97→    const objectWidth = clamp((canvasImage?.width || 0.3) * stageWidth, 56, stageWidth * 0.95);
 98→    const objectHeight = clamp((canvasImage?.height || 0.3) * stageHeight, 56, stageHeight * 0.95);
 99→    const x = clamp((canvasImage?.x || 0) * stageWidth, 0, Math.max(0, stageWidth - objectWidth));
100→    const y = clamp((canvasImage?.y || 0) * stageHeight, 0, Math.max(0, stageHeight - objectHeight));
101→
102→    return (
103→        <>
104→            <KonvaImage
105→                x={x}
106→                y={y}
107→                width={objectWidth}
108→                height={objectHeight}
109→                image={loadedImage}
110→                draggable={canInteract}
111→                rotation={canvasImage?.rotation || 0}
112→                scaleX={canvasImage?.scaleX === -1 ? -1 : 1}
113→                shadowColor="rgba(0,0,0,0.24)"
114→                shadowBlur={8}
115→                shadowOffsetY={3}
116→                onClick={canInteract ? onSelect : undefined}
117→                onTap={canInteract ? onSelect : undefined}
118→                onDragEnd={onDragEnd}
119→            />
120→            {isSelected && (
121→                <Rect
122→                    x={x}
123→                    y={y}
124→                    width={objectWidth}
125→                    height={objectHeight}
126→                    stroke="#2f80ed"
127→                    strokeWidth={1.6}
128→                    dash={[6, 4]}
129→                    rotation={canvasImage?.rotation || 0}
130→                    listening={false}
131→                />
132→            )}
133→        </>
134→    );
135→};
