1068→            return;
1069→        }
1070→        if(!session){
1071→            if(openAuthModal){
1072→                openAuthModal();
1073→            }
1074→            event.preventDefault();
1075→            return;
1076→        }
1077→
1078→        setDraggingStampType(stampType);
1079→        if(event.dataTransfer){
1080→            event.dataTransfer.effectAllowed = "copy";
1081→            event.dataTransfer.setData("application/x-iskrib-stamp", stampType);
1082→            event.dataTransfer.setData("text/plain", stampType);
1083→        }
1084→    };
1085→
1086→    const handleStampDragEnd = () => {
1087→        setDraggingStampType("");
1088→        setIsDropActive(false);
1089→    };
1090→
1091→    const handleStageDragOver = (event) => {
1092→        if(activeTool !== "stamp"){
1093→            return;
1094→        }
1095→        const transferredStamp = event.dataTransfer?.getData("application/x-iskrib-stamp");
1096→        if(!draggingStampType && !STAMP_ICONS[transferredStamp]){
1097→            return;
1098→        }
1099→        event.preventDefault();
1100→        if(event.dataTransfer){
1101→            event.dataTransfer.dropEffect = "copy";
1102→        }
1103→        if(!isDropActive){
1104→            setIsDropActive(true);
1105→        }
1106→    };
1107→
1108→    const handleStageDragLeave = () => {
1109→        if(isDropActive){
1110→            setIsDropActive(false);
1111→        }
1112→    };
1113→
1114→    const handleStageDrop = (event) => {
1115→        if(activeTool !== "stamp"){
1116→            return;
1117→        }
1118→        event.preventDefault();
1119→
1120→        const droppedStampType = event.dataTransfer?.getData("application/x-iskrib-stamp") || draggingStampType;
1121→        const stageContainer = stageRef.current?.container();
1122→        if(!stageContainer || !STAMP_ICONS[droppedStampType]){
1123→            setDraggingStampType("");
1124→            setIsDropActive(false);
1125→            return;
1126→        }
1127→
1128→        const stageRect = stageContainer.getBoundingClientRect();
1129→        const localX = event.clientX - stageRect.left;
1130→        const localY = event.clientY - stageRect.top;
1131→
1132→        const normalizedX = localX / stageRect.width;
1133→        const normalizedY = localY / stageRect.height;
1134→        addStampAt({
1135→            stampType: droppedStampType,
1136→            x: normalizedX,
1137→            y: normalizedY
1138→        });
1139→
1140→        setDraggingStampType("");
1141→        setIsDropActive(false);
1142→    };
1143→
1144→    const stamps = stampData?.stamps || [];
1145→    const marginItems = marginData?.items || [];
1146→    const docDoodles = parsedCanvasDoc?.doodles || [];
1147→    const doodleItems = marginItems.filter((item) => item?.item_type === "doodle");
1148→    const liveDoodleItems = Object.values(liveDoodlesByClient);
1149→    const stickyItems = marginItems.filter((item) => item?.item_type === "sticky");
1150→    const currentUserId = user?.userData?.[0]?.id;
1151→
1152→    return (
1153→        <div className="canvas-viewer-root">
1154→            <div className="canvas-stamp-toolbar">
1155→                <span className="canvas-stamp-label">Community Margin</span>
1156→                <button
1157→                    type="button"
1158→                    className={`canvas-tool-btn ${activeTool === "stamp" ? "is-active" : ""}`}
1159→                    onClick={() => setActiveTool("stamp")}
1160→                >
1161→                    Stamps
1162→                </button>
1163→                <button
1164→                    type="button"
