1166→                    onClick={() => setActiveTool("doodle")}
1167→                >
1168→                    Doodle
1169→                </button>
1170→
1171→                {activeTool === "stamp" && Object.entries(STAMP_ICONS).map(([stampType, icon]) => (
1172→                    <button
1173→                        key={stampType}
1174→                        type="button"
1175→                        className={`canvas-stamp-btn ${activeStampType === stampType ? "is-active" : ""}`}
