1185→
1186→                {activeTool === "doodle" && (
1187→                    <div className="canvas-tool-controls">
1188→                        <div className="canvas-color-swatches">
1189→                            {DOODLE_COLOR_PRESETS.map((color) => (
1190→                                <button
1191→                                    key={color}
