1228→                onDrop={handleStageDrop}
1229→            >
1230→                <Stage
1231→                    ref={stageRef}
1232→                    width={stageWidth}
1233→                    height={stageHeight}
1234→                    onClick={handleStageClick}
1235→                    onTap={handleStageClick}
1236→                    onMouseDown={handleCanvasPointerDown}
1237→                    onTouchStart={handleCanvasPointerDown}
1238→                    onMouseMove={handleCanvasPointerMove}
1239→                    onTouchMove={handleCanvasPointerMove}
