1243→                >
1244→                    {parsedCanvasDoc?.meta?.gridEnabled && (
1245→                        <Layer listening={false}>
1246→                            {Array.from({length: Math.floor(stageWidth / GRID_SIZE) + 1}).map((_, index) => (
