1254→                            {Array.from({length: Math.floor(stageHeight / GRID_SIZE) + 1}).map((_, index) => (
1255→                                <Line
1256→                                    key={`viewer-grid-h-${index}`}
1257→                                    points={[0, index * GRID_SIZE, stageWidth, index * GRID_SIZE]}
1258→                                    stroke={parsedCanvasDoc?.meta?.theme === "dark" ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.08)"}
1259→                                    strokeWidth={1}
1260→                                />
1261→                            ))}
1262→                        </Layer>
