1264→
1265→                    <Layer listening={false}>
1266→                        {docDoodles.map((doodle) => {
1267→                            const points = Array.isArray(doodle?.points)
1268→                                ? doodle.points.map((point) => Number(point)).filter((point) => !Number.isNaN(point))
1269→                                : [];
1270→                            if(points.length < 4){
1271→                                return null;
1272→                            }
1273→
1274→                            return (
1275→                                <Line
1276→                                    key={`doc-doodle-${doodle.id}`}
1277→                                    points={points.map((point, index) => (
1278→                                        index % 2 === 0 ? point * stageWidth : point * stageHeight
1279→                                    ))}
1280→                                    stroke={doodle?.color || "#5f92ff"}
1281→                                    strokeWidth={Number(doodle?.size) || 2.8}
1282→                                    lineCap="round"
1283→                                    lineJoin="round"
1284→                                    tension={0.1}
1285→                                />
1286→                            );
1287→                        })}
1288→                    </Layer>
1289→
1290→                    <Layer>
1291→                        {sortedObjects.map((object) => {
1292→                            if(object.kind === "snippet"){
1293→                                const snippet = object.payload;
1294→                                const metrics = getSnippetMetrics(snippet, stageWidth);
1295→                                const brush = FONT_BRUSHES[snippet.fontStyle] || FONT_BRUSHES.serif;
1296→                                const snippetX = clamp(snippet.x * stageWidth, 0, Math.max(0, stageWidth - metrics.width));
1297→                                const snippetY = clamp(snippet.y * stageHeight, 0, Math.max(0, stageHeight - metrics.height));
1298→
1299→                                return (
1300→                                    <Text
1301→                                        key={snippet.id}
1302→                                        x={snippetX}
1303→                                        y={snippetY}
1304→                                        width={metrics.width}
1305→                                        height={metrics.height}
1306→                                        text={snippet.text}
1307→                                        fontFamily={brush.fontFamily}
1308→                                        fontStyle={brush.fontStyle}
1309→                                        fontSize={metrics.fontSize}
1310→                                        fill={parsedCanvasDoc?.meta?.theme === "dark" ? "#f8f8f8" : "#151515"}
1311→                                        align="center"
1312→                                        verticalAlign="middle"
1313→                                        padding={8}
1314→                                        wrap="word"
1315→                                        rotation={snippet.rotation || 0}
1316→                                        scaleX={snippet.scaleX === -1 ? -1 : 1}
1317→                                        onClick={(event) => handleAddStampOnObject(snippet.id, event)}
1318→                                        onTap={(event) => handleAddStampOnObject(snippet.id, event)}
1319→                                    />
1320→                                );
1321→                            }
1322→
1323→                            const image = object.payload;
1324→                            return (
1325→                                <CanvasImageNode
1326→                                    key={image.id}
1327→                                    canvasImage={image}
1328→                                    stageWidth={stageWidth}
1329→                                    stageHeight={stageHeight}
1330→                                    onStamp={(event) => handleAddStampOnObject(image.id, event)}
1331→                                />
1332→                            );
1333→                        })}
1334→                    </Layer>
1335→
1336→                    <Layer>
1337→                        {stamps.map((stamp) => {
1338→                            const canDelete = currentUserId && (stamp.user_id === currentUserId || authorId === currentUserId);
1339→                            return (
1340→                                <StampNode
1341→                                    key={stamp.id}
1342→                                    stamp={stamp}
1343→                                    stageWidth={stageWidth}
1344→                                    stageHeight={stageHeight}
1345→                                    canDelete={canDelete}
1346→                                    onDelete={() => deleteStampMutation.mutate(stamp.id)}
1347→                                />
1348→                            );
1349→                        })}
1350→                    </Layer>
1351→
1352→                    <Layer>
1353→                        {doodleItems.map((item) => {
1354→                            const canDelete = currentUserId && (item.user_id === currentUserId || authorId === currentUserId);
1355→                            const points = Array.isArray(item?.payload?.points)
1356→                                ? item.payload.points
1357→                                    .map((point) => Number(point))
1358→                                    .filter((point) => !Number.isNaN(point))
1359→                                : [];
1360→                            const stagePoints = points.map((point, index) => (
1361→                                index % 2 === 0 ? point * stageWidth : point * stageHeight
1362→                            ));
1363→                            return (
1364→                                <Line
1365→                                    key={item.id}
1366→                                    points={stagePoints}
1367→                                    stroke={item?.payload?.color || "#5f92ff"}
1368→                                    strokeWidth={Number(item?.payload?.size) || 2.8}
1369→                                    lineCap="round"
1370→                                    lineJoin="round"
1371→                                    tension={0.1}
1372→                                    onClick={() => {
1373→                                        if(canDelete){
1374→                                            deleteMarginMutation.mutate(item.id);
1375→                                        }
1376→                                    }}
1377→                                    onTap={() => {
