1380→                                        }
1381→                                    }}
1382→                                />
1383→                            );
1384→                        })}
1385→
1386→                        {liveDoodleItems.map((doodle) => (
1387→                            <Line
1388→                                key={`live-doodle-${doodle.clientId}`}
1389→                                points={doodle.points.map((point, index) => (
1390→                                    index % 2 === 0 ? point * stageWidth : point * stageHeight
1391→                                ))}
1392→                                stroke={doodle.color || "#5f92ff"}
1393→                                strokeWidth={Number(doodle.size) || 2.8}
1394→                                lineCap="round"
1395→                                lineJoin="round"
1396→                                tension={0.1}
1397→                                opacity={0.86}
1398→                                listening={false}
1399→                            />
1400→                        ))}
1401→
1402→                        {isDrawing && currentDoodlePoints.length >= 2 && (
