1409→                                lineCap="round"
1410→                                lineJoin="round"
1411→                                tension={0.1}
1412→                            />
1413→                        )}
1414→                    </Layer>
1415→
1416→                    <Layer>
1417→                        {stickyItems.map((item) => {
1418→                            const canDelete = currentUserId && (item.user_id === currentUserId || authorId === currentUserId);
1419→                            const stickyX = clamp((Number(item?.payload?.x) || 0) * stageWidth, 0, Math.max(0, stageWidth - STICKY_WIDTH));
