1421→                            return (
1422→                                <Group
1423→                                    key={item.id}
1424→                                    x={stickyX}
1425→                                    y={stickyY}
1426→                                    onClick={() => {
1427→                                        if(canDelete){
1428→                                            deleteMarginMutation.mutate(item.id);
1429→                                        }
1430→                                    }}
1431→                                    onTap={() => {
1432→                                        if(canDelete){
1433→                                            deleteMarginMutation.mutate(item.id);
1434→                                        }
1435→                                    }}
1436→                                >
1437→                                    <Rect
1438→                                        width={STICKY_WIDTH}
1439→                                        height={STICKY_HEIGHT}
1440→                                        cornerRadius={8}
1441→                                        fill={item?.payload?.color || "#fff4a8"}
1442→                                        shadowColor="rgba(0,0,0,0.18)"
1443→                                        shadowBlur={8}
1444→                                        shadowOffsetY={3}
1445→                                    />
1446→                                    <Text
1447→                                        x={10}
1448→                                        y={10}
1449→                                        width={STICKY_WIDTH - 20}
1450→                                        height={STICKY_HEIGHT - 20}
1451→                                        text={item?.payload?.text || ""}
1452→                                        fontSize={15}
1453→                                        lineHeight={1.25}
1454→                                        fill="#1b1c1e"
1455→                                        wrap="word"
1456→                                    />
1457→                                </Group>
1458→                            );
1459→                        })}
1460→                    </Layer>
1461→                </Stage>
1462→            </div>
1463→        </div>
1464→    );
1465→};
1466→
1467→export default CanvasViewer;
