/* ── Card ── */
.cards{
    position: relative;
    display: flex;
    flex-direction: column;
    justify-content: flex-start;
    align-items: center;
    width: 100%;
    min-height: fit-content;
    background-color: var(--bg-card);
    border: 1px solid var(--border-card);
    border-radius: 12px;
    overflow: hidden;
    cursor: pointer;
    transition: box-shadow 0.25s ease, transform 0.25s ease;
}
.cards:hover{
    box-shadow: 0 6px 24px rgba(0, 0, 0, 0.07);
    transform: translateY(-2px);
}

.bookmarked-content-message-container{
    position: absolute;
    top: 100px;
    background-color: rgb(72, 208, 135);
    color: rgb(255, 255, 255);
    font-size: 0.78rem;
    font-weight: 600;
    padding: 0.45rem 1rem;
    border-radius: 8px;
    width: fit-content;
    z-index: 11;
    transition: ease-in-out 0.2s;
}

/* ── Banner image ── */
.card-image-banner{
    width: 100%;
    max-height: 220px;
    object-fit: cover;
    display: block;
    border-bottom: 1px solid var(--border-card);
    transition: opacity 0.2s ease;
}
.cards:hover .card-image-banner{
    opacity: 0.95;
}

/* ── Card content area ── */
.card-content{
    display: flex;
    flex-direction: column;
    gap: 0.8rem;
    width: 100%;
    padding: 1rem 1.15rem 0.6rem 1.15rem;
    box-sizing: border-box;
}

/* ── User info row ── */
.user-info{
    display: flex;
    justify-content: space-between;
    align-items: center;
}
.user-info-child-container{
    display: flex;
    align-items: center;
    height: 100%;
    gap: 0.4rem;
    width: fit-content;
}
.user-avatar-container{
    display: flex;
    align-items: center;
    justify-content: center;
    width: fit-content;
    height: fit-content;

